// Mock Rule class for testing
class MockRule {
    constructor(path, verb, result) {
        this.path = path;
        this.verb = verb;
        this.result = result;
    }

    query(path, verb, ctx) {
        if (this.path === path && this.verb === verb) {
            return this.result;
        }
        return null;
    }

    matches(path, ctx) {
        return this.path === path;
    }

    clone() {
        return new MockRule(this.path, this.verb, this.result);
    }
}

