        const rule2 = new MockRule('/test', 'write', false);
        const policy = new _spacl_core.Policy('testPolicy', rule1, rule2);

        assert.strictEqual(policy.name, 'testPolicy');
        assert.strictEqual(policy.rules.length, 2);
        assert.strictEqual(policy.rules[0], rule1);
        assert.strictEqual(policy.rules[1], rule2);
        done();
    });

    it('test @spacl/core.Policy push method', function(done) {
        const rule1 = new MockRule('/test', 'read', true);
        const policy = new _spacl_core.Policy('testPolicy');

        assert.strictEqual(policy.rules.length, 0);

        const result = policy.push(rule1);
        assert.strictEqual(policy.rules.length, 1);
        assert.strictEqual(policy.rules[0], rule1);
        assert.strictEqual(result, policy); // should return this for chaining

        const rule2 = new MockRule('/test', 'write', false);
        policy.push(rule2);
        assert.strictEqual(policy.rules.length, 2);
        done();
    });

    it('test @spacl/core.Policy query method', function(done) {
        const allowRule = new MockRule('/allowed', 'read', true);
        const denyRule = new MockRule('/denied', 'read', false);
        const noMatchRule = new MockRule('/other', 'write', true);
        const policy = new _spacl_core.Policy('testPolicy', allowRule, denyRule, noMatchRule);

        // Test explicit allow
        assert.strictEqual(policy.query('/allowed', 'read', {}), true);

        // Test explicit deny
        assert.strictEqual(policy.query('/denied', 'read', {}), false);

        // Test no match
        assert.strictEqual(policy.query('/unknown', 'read', {}), null);

        // Test deny takes precedence over allow
        const conflictPolicy = new _spacl_core.Policy('conflict', 
            new MockRule('/conflict', 'read', true),
            new MockRule('/conflict', 'read', false)
        );
        assert.strictEqual(conflictPolicy.query('/conflict', 'read', {}), false);
        done();
    });

    it('test @spacl/core.Policy matches method', function(done) {
        const rule1 = new MockRule('/test', 'read', true);
        const rule2 = new MockRule('/other', 'write', false);
        const policy = new _spacl_core.Policy('testPolicy', rule1, rule2);

        assert.strictEqual(policy.matches('/test', {}), true);
        assert.strictEqual(policy.matches('/other', {}), true);
        assert.strictEqual(policy.matches('/unknown', {}), false);
        done();
    });

