        assert.strictEqual(deepClone.name, 'cloned');
        assert.strictEqual(deepClone.rules.length, 2);
        assert.notStrictEqual(deepClone.rules[0], rule1); // should be different objects
        assert.notStrictEqual(deepClone.rules[1], rule2);

        // Test shallow clone with same name
        const shallowClone = originalPolicy.clone(undefined, false);
        assert.strictEqual(shallowClone.name, 'original');
        assert.strictEqual(shallowClone.rules.length, 2);
        assert.strictEqual(shallowClone.rules[0], rule1); // should be same objects
        assert.strictEqual(shallowClone.rules[1], rule2);

        // Test default parameters
        const defaultClone = originalPolicy.clone();
        assert.strictEqual(defaultClone.name, 'original');
        assert.notStrictEqual(defaultClone.rules[0], rule1); // deep clone by default
        done();
    });

